// api/waitlist-decision.js
// Handles owner approve / decline actions for a waitlist entry.
//
// Called when the owner clicks the "Approve" or "Decline" button in the
// admin notification email.  The action is authenticated with an HMAC-signed
// token generated by save-waitlist-entry.js.
//
// GET  /api/waitlist-decision?action=approve|decline&token=SIGNED_TOKEN
//
// On Approve:
//   - Updates entry status to "approved" in waitlist.json
//   - Sends a confirmation email to the customer
//
// On Decline:
//   - Updates entry status to "declined" in waitlist.json
//   - Issues a full Stripe refund if depositPaid > 0 and paymentIntentId is set
//   - Optionally sends a decline email to the customer (if SMTP is configured)
//
// Required environment variables:
//   OTP_SECRET
//   GITHUB_TOKEN  (contents:write)
//   GITHUB_REPO   (defaults to kysboadi-afk/SLY-RIDES)
//   SMTP_HOST, SMTP_PORT, SMTP_USER, SMTP_PASS
//   OWNER_EMAIL
//   STRIPE_SECRET_KEY  (for refunds on decline)
import Stripe from "stripe";
import nodemailer from "nodemailer";
import { verifyDecisionToken } from "./_waitlist-token.js";
import { sendSms } from "./_textmagic.js";
import { render, WAITLIST_APPROVED, WAITLIST_DECLINED } from "./_sms-templates.js";
import { normalizePhone } from "./_bookings.js";
import { upsertContact } from "./_contacts.js";
import { updateJsonFileWithRetry } from "./_github-retry.js";

const OWNER_EMAIL   = process.env.OWNER_EMAIL || "slyservices@supports-info.com";
const GITHUB_REPO   = process.env.GITHUB_REPO || "kysboadi-afk/SLY-RIDES";
const WAITLIST_PATH = "waitlist.json";

function esc(str) {
  return String(str || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function htmlPage(title, heading, body, color = "#333") {
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${esc(title)} — SLY Rides</title>
  <style>
    body { font-family: sans-serif; max-width: 560px; margin: 60px auto; padding: 24px; text-align: center; }
    h1   { color: ${color}; }
    p    { color: #555; line-height: 1.6; }
    a    { color: #1a73e8; }
  </style>
</head>
<body>
  <h1>${heading}</h1>
  ${body}
  <p style="margin-top:32px"><a href="https://www.slytrans.com">← Return to SLY Rides</a></p>
</body>
</html>`;
}

/**
 * Load the current waitlist.json from GitHub.
 * Returns { data, sha } or null on failure.
 */
async function loadWaitlist(headers, apiUrl) {
  const resp = await fetch(apiUrl, { headers });
  if (!resp.ok) return null;
  const file = await resp.json();
  try {
    const data = JSON.parse(
      Buffer.from(file.content.replace(/\n/g, ""), "base64").toString("utf-8")
    );
    return { data, sha: file.sha };
  } catch {
    return null;
  }
}

/**
 * Save updated waitlist.json back to GitHub.
 */
async function saveWaitlist(headers, apiUrl, data, sha, message) {
  const content = Buffer.from(JSON.stringify(data, null, 2) + "\n").toString("base64");
  const body = { message, content };
  if (sha) body.sha = sha;
  const resp = await fetch(apiUrl, {
    method:  "PUT",
    headers: { ...headers, "Content-Type": "application/json" },
    body:    JSON.stringify(body),
  });
  if (!resp.ok) {
    const text = await resp.text();
    throw new Error(`GitHub PUT failed: ${resp.status} ${text}`);
  }
}

export default async function handler(req, res) {
  // This endpoint only accepts GET (email link click)
  if (req.method !== "GET") return res.status(405).send("Method Not Allowed");

  const { action, token } = req.query || {};

  if (!action || !["approve", "decline"].includes(action)) {
    return res
      .status(400)
      .send(htmlPage("Invalid Request", "❌ Invalid Request", "<p>The action must be <code>approve</code> or <code>decline</code>.</p>", "#dc3545"));
  }

  // ── Verify HMAC token ─────────────────────────────────────────────────────
  const tokenData = verifyDecisionToken(token);
  if (!tokenData) {
    return res
      .status(400)
      .send(htmlPage("Invalid Token", "❌ Invalid or Tampered Link", "<p>This link is invalid or has been tampered with. Please use the original link from the notification email.</p>", "#dc3545"));
  }

  const { vehicleId, entryId } = tokenData;

  // ── Load waitlist.json from GitHub ────────────────────────────────────────
  const githubToken = process.env.GITHUB_TOKEN;
  if (!githubToken) {
    console.error("waitlist-decision: GITHUB_TOKEN not set");
    return res
      .status(500)
      .send(htmlPage("Server Error", "⚙️ Configuration Error", "<p>The server is not configured correctly. Please contact the site administrator.</p>", "#dc3545"));
  }

  const apiUrl = `https://api.github.com/repos/${GITHUB_REPO}/contents/${WAITLIST_PATH}`;
  const ghHeaders = {
    Authorization:          `Bearer ${githubToken}`,
    Accept:                 "application/vnd.github+json",
    "X-GitHub-Api-Version": "2022-11-28",
  };

  // Initial load used only for entry validation (not-found / already-decided checks)
  let wlData;
  try {
    const loaded = await loadWaitlist(ghHeaders, apiUrl);
    if (!loaded) throw new Error("Could not load waitlist.json");
    wlData = loaded.data;
  } catch (err) {
    console.error("waitlist-decision: load error:", err);
    return res
      .status(500)
      .send(htmlPage("Server Error", "⚙️ Server Error", "<p>Could not load the waitlist. Please try again later.</p>", "#dc3545"));
  }

  // ── Find the entry ────────────────────────────────────────────────────────
  const list = wlData[vehicleId];
  if (!Array.isArray(list)) {
    return res
      .status(404)
      .send(htmlPage("Not Found", "❌ Entry Not Found", "<p>No waitlist entries found for this vehicle.</p>", "#dc3545"));
  }

  const idx = list.findIndex((e) => e.entryId === entryId);
  if (idx === -1) {
    return res
      .status(404)
      .send(htmlPage("Not Found", "❌ Entry Not Found", "<p>This waitlist entry could not be found. It may have already been removed.</p>", "#dc3545"));
  }

  const entry = list[idx];

  // ── Guard: already decided ────────────────────────────────────────────────
  if (entry.status === "approved" || entry.status === "declined") {
    const statusLabel = entry.status === "approved" ? "✅ Approved" : "❌ Declined";
    return res
      .status(200)
      .send(
        htmlPage(
          "Already Decided",
          "ℹ️ Already Processed",
          `<p>This entry for <strong>${esc(entry.name)}</strong> has already been marked as <strong>${statusLabel}</strong>.</p>`,
          "#888"
        )
      );
  }

  // ── Apply decision with retry-on-409 ─────────────────────────────────────
  const newStatus = action === "approve" ? "approved" : "declined";
  const decidedAt = new Date().toISOString();

  // Closure-based load/save so updateJsonFileWithRetry always re-fetches the
  // latest SHA before each write attempt.
  const loadFn = async () => {
    const result = await loadWaitlist(ghHeaders, apiUrl);
    if (!result) throw new Error("Could not load waitlist.json");
    return result;
  };
  const saveFn = (data, fileSha, message) => saveWaitlist(ghHeaders, apiUrl, data, fileSha, message);

  try {
    await updateJsonFileWithRetry({
      load:  loadFn,
      apply: (data) => {
        const vList = data[vehicleId];
        if (!Array.isArray(vList)) return;
        const i = vList.findIndex((e) => e.entryId === entryId);
        if (i === -1) return;
        // Idempotent: only update if not already decided
        if (vList[i].status !== "approved" && vList[i].status !== "declined") {
          vList[i] = { ...vList[i], status: newStatus, decidedAt };
        }
      },
      save:    saveFn,
      message: `Waitlist ${newStatus}: ${vehicleId} — ${entry.name} (#${entry.position})`,
    });
  } catch (err) {
    console.error("waitlist-decision: save error:", err);
    return res
      .status(500)
      .send(htmlPage("Server Error", "⚙️ Save Error", "<p>Could not update the waitlist. Please try again.</p>", "#dc3545"));
  }

  // ── Stripe refund on decline ──────────────────────────────────────────────
  let refundNote = "";
  if (action === "decline" && entry.depositPaid > 0 && entry.paymentIntentId) {
    try {
      if (!process.env.STRIPE_SECRET_KEY) {
        console.warn("waitlist-decision: STRIPE_SECRET_KEY not set — skipping refund");
        refundNote = "<p style='color:#dc3545'>⚠️ Stripe is not configured — refund must be issued manually.</p>";
      } else {
        const stripe = new Stripe(process.env.STRIPE_SECRET_KEY);
        await stripe.refunds.create({
          payment_intent: entry.paymentIntentId,
        });
        refundNote = `<p style='color:#28a745'>💰 $${entry.depositPaid} deposit has been automatically refunded to the customer.</p>`;
      }
    } catch (stripeErr) {
      console.error("waitlist-decision: Stripe refund error:", stripeErr);
      refundNote = `<p style='color:#dc3545'>⚠️ Stripe refund failed: ${esc(stripeErr.message)} — please refund manually from the Stripe dashboard.</p>`;
    }
  }

  // ── Send email notifications ──────────────────────────────────────────────
  if (process.env.SMTP_HOST && process.env.SMTP_USER && process.env.SMTP_PASS) {
    const transporter = nodemailer.createTransport({
      host:   process.env.SMTP_HOST,
      port:   parseInt(process.env.SMTP_PORT || "587"),
      secure: parseInt(process.env.SMTP_PORT || "587") === 465,
      auth:   { user: process.env.SMTP_USER, pass: process.env.SMTP_PASS },
    });

    if (action === "approve") {
      // ── Approval email to customer ─────────────────────────────────────────
      try {
        await transporter.sendMail({
          from:    `"Sly Transportation Services LLC" <${process.env.SMTP_USER}>`,
          to:      entry.email,
          subject: `✅ You're Approved! Waitlist Confirmed — ${entry.vehicleName || vehicleId} | SLY Transportation`,
          text: [
            `Hi ${entry.name},`,
            "",
            "Great news — your driver's license has been reviewed and your waitlist spot is officially confirmed!",
            "",
            "Waitlist Details:",
            `Vehicle          : ${entry.vehicleName || vehicleId}`,
            `Your Position    : #${entry.position}`,
            `Status           : ✅ Approved`,
            `Preferred Pickup : ${entry.preferredPickup || "Not specified"}`,
            `Preferred Return : ${entry.preferredReturn || "Not specified"}`,
            "",
            "What happens next:",
            "• When the vehicle becomes available for your preferred dates, we will contact you immediately.",
            "• You will receive a payment link to complete the full booking.",
            "• You will have 12–24 hours to complete payment.",
            "• Your $50 deposit goes toward your total rental cost.",
            "",
            `Questions? Call us at (213) 916-6606 or email ${OWNER_EMAIL}.`,
            "",
            "— Sly Transportation Services LLC Team",
          ].join("\n"),
          html: `
            <h2>✅ You're Approved!</h2>
            <p>Hi <strong>${esc(entry.name)}</strong>,</p>
            <p>Great news — your driver's license has been reviewed and your waitlist spot is officially confirmed!</p>
            <p style="background:#d4edda;padding:10px;border-left:4px solid #28a745;margin-bottom:16px">
              <strong>✅ Status: Approved</strong> — You are #${entry.position} in the queue.
            </p>
            <table style="border-collapse:collapse;width:100%;margin-bottom:16px">
              <tr><td style="padding:8px;border:1px solid #ddd"><strong>Vehicle</strong></td><td style="padding:8px;border:1px solid #ddd">${esc(entry.vehicleName || vehicleId)}</td></tr>
              <tr><td style="padding:8px;border:1px solid #ddd"><strong>Your Position</strong></td><td style="padding:8px;border:1px solid #ddd"><strong>#${entry.position}</strong></td></tr>
              <tr><td style="padding:8px;border:1px solid #ddd"><strong>Status</strong></td><td style="padding:8px;border:1px solid #ddd">✅ Approved</td></tr>
              <tr><td style="padding:8px;border:1px solid #ddd"><strong>Preferred Pickup</strong></td><td style="padding:8px;border:1px solid #ddd">${esc(entry.preferredPickup || "Not specified")}</td></tr>
              <tr><td style="padding:8px;border:1px solid #ddd"><strong>Preferred Return</strong></td><td style="padding:8px;border:1px solid #ddd">${esc(entry.preferredReturn || "Not specified")}</td></tr>
              <tr><td style="padding:8px;border:1px solid #ddd"><strong>Deposit Paid</strong></td><td style="padding:8px;border:1px solid #ddd">$${entry.depositPaid} <em style="font-size:12px;color:#888">(applied toward your rental)</em></td></tr>
            </table>
            <h3 style="color:#333">What happens next:</h3>
            <ul>
              <li>When the vehicle becomes available for your preferred dates, we'll contact you right away.</li>
              <li>You'll receive a payment link to complete the full booking.</li>
              <li>You have <strong>12–24 hours</strong> to complete payment — otherwise the next person in line is contacted.</li>
              <li>Your <strong>$50 deposit goes toward your total rental cost</strong>.</li>
            </ul>
            <p>Questions? Call us at <strong>(213) 916-6606</strong> or email <a href="mailto:${esc(OWNER_EMAIL)}">${esc(OWNER_EMAIL)}</a>.</p>
            <p><strong>Sly Transportation Services LLC Team 🚗</strong></p>
          `,
        });
      } catch (emailErr) {
        console.error("waitlist-decision: approval email failed:", emailErr);
      }
    } else {
      // ── Decline email to customer ──────────────────────────────────────────
      const refundLine = entry.depositPaid > 0 && entry.paymentIntentId
        ? `Your $${entry.depositPaid} deposit will be refunded to your original payment method within 5–10 business days.`
        : "";
      try {
        await transporter.sendMail({
          from:    `"Sly Transportation Services LLC" <${process.env.SMTP_USER}>`,
          to:      entry.email,
          subject: `Waitlist Update — ${entry.vehicleName || vehicleId} | SLY Transportation`,
          text: [
            `Hi ${entry.name},`,
            "",
            "Thank you for your interest in renting with Sly Transportation Services.",
            "After reviewing your application, we are unable to approve your waitlist request at this time.",
            refundLine ? `\n${refundLine}` : "",
            "",
            `If you have questions, please contact us at (213) 916-6606 or ${OWNER_EMAIL}.`,
            "",
            "— Sly Transportation Services LLC Team",
          ].filter(Boolean).join("\n"),
          html: `
            <h2>Waitlist Application Update</h2>
            <p>Hi <strong>${esc(entry.name)}</strong>,</p>
            <p>Thank you for your interest in renting with Sly Transportation Services. After reviewing your application, we are unable to approve your waitlist request at this time.</p>
            ${refundLine ? `<p style="background:#d4edda;padding:10px;border-left:4px solid #28a745">💰 ${esc(refundLine)}</p>` : ""}
            <p>If you have questions, please contact us at <strong>(213) 916-6606</strong> or <a href="mailto:${esc(OWNER_EMAIL)}">${esc(OWNER_EMAIL)}</a>.</p>
            <p><strong>Sly Transportation Services LLC Team 🚗</strong></p>
          `,
        });
      } catch (emailErr) {
        console.error("waitlist-decision: decline email failed:", emailErr);
      }
    }
  }

  // ── Build next-in-queue notification (optional) ───────────────────────────
  // If the top approved entry was declined and there's a next pending entry, notify them.
  let nextNote = "";
  if (action === "decline") {
    const nextPending = wlData[vehicleId].find(
      (e, i) => i !== idx && e.status === "pending"
    );
    if (nextPending) {
      nextNote = `<p>ℹ️ The next pending entry in the queue is <strong>${esc(nextPending.name)}</strong> (${esc(nextPending.email)}) at position #${nextPending.position}.</p>`;
    }
  }

  // ── Decision SMS ──────────────────────────────────────────────────────────
  if (entry.phone && process.env.TEXTMAGIC_USERNAME && process.env.TEXTMAGIC_API_KEY) {
    const normalizedPhone = normalizePhone(entry.phone);
    try {
      if (action === "approve") {
        await sendSms(
          normalizedPhone,
          render(WAITLIST_APPROVED, {
            customer_name: entry.name,
            vehicle:       entry.vehicleName || vehicleId,
            booking_link:  "https://www.slytrans.com/cars.html",
          })
        );
      } else {
        await sendSms(
          normalizedPhone,
          render(WAITLIST_DECLINED, { customer_name: entry.name })
        );
      }
    } catch (smsErr) {
      console.error("waitlist-decision: decision SMS failed:", smsErr);
    }
  }

  // ── TextMagic contact: add 'approved' tag on approval ────────────────────
  if (action === "approve" && entry.phone) {
    try {
      await upsertContact(normalizePhone(entry.phone), entry.name, { addTags: ["approved"] });
    } catch (contactErr) {
      console.error("waitlist-decision: TextMagic contact upsert failed:", contactErr);
    }
  }

  // ── Return success HTML page ──────────────────────────────────────────────
  if (action === "approve") {
    return res.status(200).send(
      htmlPage(
        "Approved",
        "✅ Renter Approved",
        `<p><strong>${esc(entry.name)}</strong> has been approved and a confirmation email has been sent to <strong>${esc(entry.email)}</strong>.</p>
         <p>They are #${entry.position} in the queue for the ${esc(vehicleId)} vehicle.</p>`,
        "#28a745"
      )
    );
  } else {
    return res.status(200).send(
      htmlPage(
        "Declined",
        "❌ Renter Declined",
        `<p><strong>${esc(entry.name)}</strong>'s application has been declined.</p>
         ${refundNote}
         ${nextNote}`,
        "#dc3545"
      )
    );
  }
}
